<template>
    <div class="container">
        <el-breadcrumb separator-class="el-icon-arrow-right">
            <el-breadcrumb-item :to="{ path: '/home' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item>商品管理</el-breadcrumb-item>
            <el-breadcrumb-item>商品列表</el-breadcrumb-item>
        </el-breadcrumb>
        <el-card class="box-card">
            <el-button type="primary" style="margin-bottom: 20px;" @click="getParentCategoryList()">添加分类</el-button>
                <tree-table border :show-index="true" :selection-type="false"  :expand-type="false" :data="categoryList" :columns="columns">
                    <template slot="valid" slot-scope="scope">
                        <i v-if="scope.row.cat_deleted==false" style="color:lightgreen" class="el-icon-success"></i>
                        <i v-if="scope.row.cat_deleted==true"  style="color:#CD3131" class="el-icon-error"></i>
                    </template> 
                    <template slot="order" slot-scope="scope">
                        <el-tag type="primary" v-if="scope.row.cat_level===0" size="mini">一级</el-tag>
                        <el-tag type="success" v-if="scope.row.cat_level===1" size="mini">二级</el-tag>
                        <el-tag type="warning" v-if="scope.row.cat_level===2" size="mini">三级</el-tag>
                    </template>
                    <template slot="option" slot-scope="scope">
                        <el-button type="primary" icon="el-icon-edit" size="mini">编辑</el-button>
                        <el-button type="danger" icon="el-icon-delete" size="mini">删除</el-button>
                    </template>
                </tree-table>
                <el-pagination
                    @size-change="handleSizeChange"
                    @current-change="handleCurrentChange"
                    :current-page="queryInfo.pagenum"
                    :page-sizes="[5, 10, 15]"
                    :page-size="queryInfo.pagesize"
                    layout="total, sizes, prev, pager, next, jumper"
                    :total="this.total">
                </el-pagination>
        </el-card>
        <el-dialog title="提示" :visible.sync="addCateDialogVisible" width="50%" @close="addCateDialogClose">
            <span>
                <el-form :model="addCateForm" :rules="rules" ref="addCateFormRef" label-width="100px">
                    <el-form-item label="分类名称" prop="cat_name">
                        <el-input v-model="addCateForm.cat_name"></el-input>
                    </el-form-item>
                    <el-form-item label="父级分类">
                        <el-cascader filterable clearable v-model="cascaderValue" :options="parentCategoryList" :props="{ expandTrigger: 'hover',label:'cat_name',value:'cat_id',children:'children',checkStrictly:'true' }" @change="parentCateChange"></el-cascader>
                    </el-form-item>
                </el-form>
            </span>
            <span slot="footer" class="dialog-footer">
                <el-button @click="addCateDialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="addCate">确 定</el-button>
            </span>
        </el-dialog>
    </div>
</template>

<script>

export default{
    data(){
        return{
            queryInfo:{
                type:3,
                pagenum:1,
                pagesize:5
            },
            addCateDialogVisible:false,
            categoryList:[],
            parentCategoryList:[],
            cascaderValue:[],
            total:0,
            addCateForm:{
                cat_name:'',
                cat_level:0,
                cat_pid:0
            },
            columns:[{
                label:"分类名称",
                prop:"cat_name",
            },{
                label:"是否有效",
                // prop:"cat_deleted",
                align:'center',
                type:'template',
                template:'valid'
            },{
                label:"排序",
                align:'center',
                type:'template',
                template:'order'
            },{
                label:"操作",
                align:'center',
                type:'template',
                template:'option'
            }],
            rules:{
                cat_name:[
                    { required: true, message: '用户名为必填项', trigger: 'blur' },
                ],
            },
        }
    },
    created(){
        this.getCategoryList()
    },
    methods:{
        async getCategoryList(){
            const{data:result}=await this.$http.get(`categories`,{params:this.queryInfo})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            this.total=result.data.total
            this.categoryList=result.data.result
            // console.log(result.data);
            // console.log(result.data.result);
        },
        handleSizeChange(newSize){
            this.queryInfo.pagesize=newSize
            this.getCategoryList()
        },
        handleCurrentChange(newCurrent){
            this.queryInfo.pagenum=newCurrent
            this.getCategoryList()
        },
        async getParentCategoryList(){
            this.addCateDialogVisible=true
            const{data:result}=await this.$http.get(`categories`,{params:{type:2}})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            // console.log(result.data)
            this.parentCategoryList=result.data
        },
        parentCateChange(){
            // console.log(this.cascaderValue);
            if(this.cascaderValue.length>0){
                this.addCateForm.cat_pid=this.cascaderValue[this.cascaderValue.length-1]
                this.addCateForm.cat_level=this.cascaderValue.length
                return
            }
            else{
                this.addCateForm.cat_pid=0
                this.addCateForm.cat_level=0
            }
        },
        addCate(){
            this.$refs.addCateFormRef.validate(async (valid)=>{
                if(!valid){
                    return
                }else{
                    const{data:result}=await this.$http.post(`categories`,this.addCateForm)
                    if(result.meta.status!==201){return this.$message.error(result.meta.msg);}
                    else{this.$message.success(result.meta.msg);}
                }
                this.getCategoryList()
                this.addCateDialogVisible = false
            })
        },
        addCateDialogClose(){
            this.$refs.addCateFormRef.resetFields()
            this.addCateForm.cat_pid=0
            this.addCateForm.cat_level=0
            this.cascaderValue=[]
        }
    }
}
</script>

<style lang="less" scoped>
.container{
    padding: 20px;
    width: 100%;
    background-color: aliceblue;
    box-sizing: border-box;
    .el-breadcrumb{
        font-size: 12px;
    }
    .el-card{
        margin: 20px 0 20px 0;
        padding: 10px;
        .el-pagination{
            margin-left: 50%;
            transform: translate(-50%,10px);
        }
        
    }
}
</style>