<template>
<div class="container">
    <el-breadcrumb separator-class="el-icon-arrow-right">
        <el-breadcrumb-item :to="{ path: '/home' }">首页</el-breadcrumb-item>
        <el-breadcrumb-item>活动管理</el-breadcrumb-item>
        <el-breadcrumb-item>活动列表</el-breadcrumb-item>
    </el-breadcrumb>
    <el-card>
        <el-alert title="注意：只允许为三级选项设置参数！" type="warning" show-icon :closable=false>
        </el-alert>

        <el-row style="margin:20px 0;">
            <el-col>
                <span>请选择商品分类：</span>
                <el-cascader v-model="cascaderValue" :options="categoryList" 
                :props="{ expandTrigger: 'hover',label:'cat_name',value:'cat_id',children:'children'}"  @change="handleChange"></el-cascader>
            </el-col>
        </el-row>
        <el-tabs type="border-card" v-model="activeName" @tab-click="handleTabClick">
            <el-tab-pane label="用户管理" name="many">
                <el-button type="primary"  size="mini" :disabled="isButDisable" @click="addAttributeDialog">添加属性</el-button>
                <el-table border stripe :data="dynamicTableData">
                    <el-table-column type="expand">
                        <template slot-scope="scope">
                            <el-tag v-for="(item,index) in scope.row.attr_vals" :key="index" closable @close="handleClose(index,scope.row)">{{item}}</el-tag>
                                <el-input style="width:120px;" class="input-new-tag" v-if="scope.row.inputVisible" v-model="scope.row.inputValue" ref="saveTagInput" size="small" @keyup.enter.native="handleInputConfirm(scope.row)" @blur="handleInputConfirm(scope.row)"></el-input>
                                <el-button v-else class="button-new-tag" size="small" @click="showInput(scope.row)">+ New Tag</el-button>
                        </template>
                    </el-table-column>
                    <el-table-column type="index" label="顺序"></el-table-column>
                    <el-table-column prop="attr_name" label="属性名称"></el-table-column>
                    <el-table-column label="操作">
                        <template slot-scope="scope">
                            <el-button type="primary" icon="el-icon-edit" size="mini" @click="showEditDialog(scope.row.attr_id)">编辑</el-button>
                            <el-button type="danger" icon="el-icon-delete" size="mini" @click="DeleteAttribute(scope.row.attr_id)">删除</el-button>
                        </template>
                    </el-table-column>
                </el-table>
            </el-tab-pane>
            <el-tab-pane label="配置管理" name="only">
                <el-button type="primary"  size="mini" :disabled="isButDisable" @click="addAttributeDialog">添加属性</el-button>
                <el-table border stripe :data="staticTableData">
                    <el-table-column type="expand">
                        <template slot-scope="scope">
                            <el-tag v-for="(item,index) in scope.row.attr_vals" :key="index" closable @close="handleClose(index,scope.row)">{{item}}</el-tag>
                                <el-input style="width:120px;" class="input-new-tag" v-if="scope.row.inputVisible" v-model="scope.row.inputValue" ref="saveTagInput" size="small" @keyup.enter.native="handleInputConfirm(scope.row)" @blur="handleInputConfirm(scope.row)"></el-input>
                                <el-button v-else class="button-new-tag" size="small" @click="showInput(scope.row)">+ New Tag</el-button>
                        </template>
                    </el-table-column>
                    <el-table-column type="index" label="顺序"></el-table-column>
                    <el-table-column prop="attr_name" label="属性名称"></el-table-column>
                    <el-table-column label="操作">
                        <template slot-scope="scope">
                            <el-button type="primary" icon="el-icon-edit" size="mini" @click="showEditDialog(scope.row.attr_id)">编辑</el-button>
                            <el-button type="danger" icon="el-icon-delete" size="mini" @click="DeleteAttribute(scope.row.attr_id)">删除</el-button>
                        </template>
                    </el-table-column>
                </el-table>
            </el-tab-pane>
        </el-tabs>
    </el-card>

    <el-dialog :title="'提示'+titleText" :visible.sync="dialogVisible" width="50%" @close="addAttributeFormClose">
        <el-form :model="addAttributeForm" :rules="addAttributeFormRules" ref="addAttributeFormRef" label-width="100px">
                <el-form-item :label="titleText" prop="attr_name">
                    <el-input v-model="addAttributeForm.attr_name"></el-input>
                </el-form-item>
        </el-form>
        <span slot="footer" class="dialog-footer">
            <el-button @click="dialogVisible=false">取 消</el-button>
            <el-button type="primary" @click="sureAddAttribute">确 定</el-button>
        </span>
    </el-dialog>

    <el-dialog :title="'提示'+titleText" :visible.sync="editDialogVisible" width="50%" @close="editAttributeFormClose">
        <el-form :model="editAttributeForm" :rules="editAttributeFormRules" ref="editAttributeFormRef" label-width="100px">
                <el-form-item :label="titleText" prop="attr_name">
                    <el-input v-model="editAttributeForm.attr_name"></el-input>
                </el-form-item>
        </el-form>
        <span slot="footer" class="dialog-footer">
            <el-button @click="editDialogVisible=false">取 消</el-button>
            <el-button type="primary" @click="sureEditAttribute">确 定</el-button>
        </span>
    </el-dialog>
</div>
</template>

<script>
export default{
    data(){
        return{
            categoryList:[],
            cascaderValue:[],
            activeName:'many',
            dynamicTableData:null,
            staticTableData:null,
            dialogVisible:false,
            editDialogVisible:false,
            // inputVisible:false,
            // inputValue:null,
            addAttributeForm:{
                attr_name:''
            },
            editAttributeForm:{
                attr_name:''
            },
            editAttributeFormRules:{
                attr_name:[
                    { required: true, message: '参数/属性为必填项', trigger: 'blur' },
                ]
            },
            addAttributeFormRules:{
                attr_name:[
                    { required: true, message: '参数/属性为必填项', trigger: 'blur' },
                ]
            }
        }
    },
    created(){
        this.getCategoryList()
    },
    methods:{
        async getCategoryList(){
            const{data:result}=await this.$http.get(`categories`)
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            this.categoryList=result.data
            // console.log(result.data);
        },
        handleTabClick(){
            // console.log(this.activeName);
            this.getParamsData()
        },
        handleChange(){
            this.getParamsData()
        },
        async getParamsData(){
            if(this.cascaderValue.length!==3){
                this.cascaderValue=[]
                // 防止列表按钮依旧可以操作造成不必要的问题
                this.dynamicTableData=[],
                this,this.staticTableData=[]
                return
            }
            const{data:result}=await this.$http.get(`categories/${this.cateID}/attributes`,{params:{sel:this.activeName}})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            // console.log(result.data);

            result.data.forEach(item=>{
                // if(item.attr_vals!==''){
                //     item.attr_vals=item.attr_vals.split(',')
                //     item.inputVisible=false
                //     item.inputValue=null
                // }
                item.attr_vals=item.attr_vals?item.attr_vals.split(','):[]
                item.inputVisible=false
                // 初始值为空字符串是有道理的！初始值为null无法进行trim操作
                item.inputValue=''
            })

            if(this.activeName=='many'){
                this.dynamicTableData=result.data
            }else{
                this.staticTableData=result.data
            }
        },
        addAttributeDialog(){
            this.dialogVisible=true
        },
        sureAddAttribute(){
            this.$refs.addAttributeFormRef.validate(async valid=>{
                if(!valid){
                   return
                }else{
                    const{data:result}=await this.$http.post(`categories/${this.cateID}/attributes`,{attr_name:this.addAttributeForm.attr_name,attr_sel:this.activeName})
                    if(result.meta.status!==201){return this.$message.error(result.meta.msg);}
                    else{this.$message.success(result.meta.msg);}
                    // console.log(result.data);
                }
                this.getParamsData()
                this.dialogVisible=false
            })
        },
        addAttributeFormClose(){
            this.$refs.addAttributeFormRef.resetFields()
            this.dialogVisible=false
        },
        editAttributeFormClose(){
            this.$refs.editAttributeFormRef.resetFields()
            this.editDialogVisible=false
        },
        async showEditDialog(id){
            this.editDialogVisible=true
            const{data:result}=await this.$http.get(`categories/${this.cateID}/attributes/${id}`,{params:{attr_sel:this.activeName}})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            // console.log(result.data);
            this.editAttributeForm=result.data
            
        },
        sureEditAttribute(){
            this.$refs.editAttributeFormRef.validate(async valid=>{
                if(!valid){
                   return
                }else{
                    // console.log(this.activeName);
                    const{data:result}=await this.$http.put(`categories/${this.cateID}/attributes/${this.editAttributeForm.attr_id}`,{attr_name:this.editAttributeForm.attr_name,attr_sel:this.activeName})
                    if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
                    else{this.$message.success(result.meta.msg);}
                    // console.log(result.data);
                    this.getParamsData()
                }
                this.editDialogVisible=false
            })
        },
        DeleteAttribute(id){
            this.$confirm('此操作将永久删除该文件, 是否继续?', '提示', {
                confirmButtonText: '确定',
                cancelButtonText: '取消',
                type: 'warning'
            }).then(async ()=>{
                const{data:result}=await this.$http.delete(`categories/${this.cateID}/attributes/${id}`)
                if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
                else{this.$message.success(result.meta.msg);}
                this.getParamsData()
            }).catch(err=>{
                return err
            }) 
        },
        async handleInputConfirm(row){
            // console.log(row.attr_sel);
            // console.log(row.inputValue);
            if(row.inputValue.trim().length===0){
                row.inputValue=null
                row.inputVisible=false
                return
            }
            row.attr_vals.push(row.inputValue.trim())
            row.inputValue=null
            // 发起请求持久化存储
            const{data:result}=await this.$http.put(`categories/${this.cateID}/attributes/${row.attr_id}`,{attr_name:row.attr_name,attr_sel:row.attr_sel,attr_vals:row.attr_vals.join(',')})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            row.inputVisible=false
        },
        async handleClose(id,row){
            row.attr_vals.splice(id,1)
            const{data:result}=await this.$http.put(`categories/${this.cateID}/attributes/${row.attr_id}`,{attr_name:row.attr_name,attr_sel:row.attr_sel,attr_vals:row.attr_vals.join(',')})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
        },
        showInput(row){
            row.inputVisible=true
            // 点击tag标签自动获取输入框焦点
            this.$nextTick(_ => {
                this.$refs.saveTagInput.$refs.input.focus();
            });
        }
    },
    computed:{
        isButDisable(){
            if(this.cascaderValue.length==3){
                return false
            }else{
                return true
            }
        },
        cateID(){
            if(this.cascaderValue.length===3){
                return this.cascaderValue[2]
            }else{
                return null
            }
        },
        titleText(){
            if(this.activeName==='many'){
                return "动态参数"
            }else{
                return "静态属性"
            }
        }
    },
}
</script>

<style lang="less" scoped>
.container{
    padding: 20px;
    width: 100%;
    background-color: aliceblue;
    box-sizing: border-box;
    .el-breadcrumb{
        font-size: 12px;
    }
    .el-card{
        margin: 20px 0 20px 0;
        padding: 10px;
        .el-table{
            margin-top: 20px;
            .el-tag , .el-button , .el-input{
                margin-left: 20px;
                margin-top: 10px;
            }
        }
    }
}
</style>